#include <cassert>
#include <chrono>
#include <cfloat>
#include <cmath>
#include <cstdlib>
#include <list>
#include <iostream>
#include <cuda_runtime.h>
#include "MD.h"
#include "reference.h"
#include "utils.h"

// CUDA kernel implementing the md logic
__global__ void md_kernel(
    const POSVECTYPE* __restrict position,
    FORCEVECTYPE* __restrict force,
    const int* __restrict neighborList, 
    const int nAtom,
    const int maxNeighbors, 
    const FPTYPE lj1_t,
    const FPTYPE lj2_t,
    const FPTYPE cutsq_t )
{
  uint idx = blockIdx.x * blockDim.x + threadIdx.x;

  if (idx < nAtom) {
    POSVECTYPE ipos = position[idx];
    FORCEVECTYPE f = zero;

    int j = 0;
    while (j < maxNeighbors)
    {
      int jidx = neighborList[j * nAtom + idx];

      POSVECTYPE jpos = position[jidx];

      FPTYPE delx = ipos.x - jpos.x;
      FPTYPE dely = ipos.y - jpos.y;
      FPTYPE delz = ipos.z - jpos.z;
      FPTYPE r2inv = delx*delx + dely*dely + delz*delz;

      if (r2inv > 0 && r2inv < cutsq_t)
      {
        r2inv = (FPTYPE)1.0 / r2inv;
        FPTYPE r6inv = r2inv * r2inv * r2inv;
        FPTYPE forceC = r2inv*r6inv*(lj1_t*r6inv - lj2_t);

        f.x += delx * forceC;
        f.y += dely * forceC;
        f.z += delz * forceC;
      }
      j++;
    }
    force[idx] = f;
  }
}

void md (
    const POSVECTYPE* __restrict position,
    FORCEVECTYPE* __restrict force,
    const int* __restrict neighborList, 
    const int nAtom,
    const int maxNeighbors, 
    const FPTYPE lj1_t,
    const FPTYPE lj2_t,
    const FPTYPE cutsq_t )
{
  // Launch configuration: 256 threads per block, enough blocks to cover nAtom
  const int threads_per_block = 256;
  const int num_blocks = (nAtom + threads_per_block - 1) / threads_per_block;

  md_kernel<<<num_blocks, threads_per_block>>>(position, force, neighborList, nAtom, maxNeighbors, lj1_t, lj2_t, cutsq_t);

  // Ensure kernel completion before returning (synchronous behavior similar to OpenMP target region end)
  cudaDeviceSynchronize();
}

int main(int argc, char** argv)
{
  if (argc != 3) {
    printf("usage: %s <class size> <iteration>", argv[0]);
    return 1;
  }

  int sizeClass = atoi(argv[1]);
  int iteration = atoi(argv[2]);
  const int probSizes[] = { 12288, 24576, 36864, 73728 };
  assert(sizeClass >= 0 && sizeClass < 4);
  assert(iteration >= 0);

  int nAtom = probSizes[sizeClass];

  // Host allocation
  POSVECTYPE* h_position = (POSVECTYPE*) malloc(nAtom * sizeof(POSVECTYPE));
  FORCEVECTYPE* h_force = (FORCEVECTYPE*) malloc(nAtom * sizeof(FORCEVECTYPE));
  int *h_neighborList = (int*) malloc(maxNeighbors * nAtom * sizeof(int));

  std::cout << "Initializing test problem (this can take several minutes for large problems).\n";

  srand(123);

  for (int i = 0; i < nAtom; i++)
  {
    h_position[i].x = rand() % domainEdge;
    h_position[i].y = rand() % domainEdge;
    h_position[i].z = rand() % domainEdge;
  }

  std::cout << "Finished.\n";
  int totalPairs = buildNeighborList<FPTYPE, POSVECTYPE>(nAtom, h_position, h_neighborList);
  std::cout << totalPairs << " of " << nAtom*maxNeighbors
            << " pairs within cutoff distance = "
            << 100.0 * ((double)totalPairs / (nAtom*maxNeighbors)) << " %\n";

  // Device allocation
  POSVECTYPE* d_position;
  FORCEVECTYPE* d_force;
  int* d_neighborList;

  cudaMalloc(&d_position, nAtom * sizeof(POSVECTYPE));
  cudaMalloc(&d_force, nAtom * sizeof(FORCEVECTYPE));
  cudaMalloc(&d_neighborList, maxNeighbors * nAtom * sizeof(int));

  // Copy data to device
  cudaMemcpy(d_position, h_position, nAtom * sizeof(POSVECTYPE), cudaMemcpyHostToDevice);
  cudaMemcpy(d_neighborList, h_neighborList, maxNeighbors * nAtom * sizeof(int), cudaMemcpyHostToDevice);

  // Run initial md
  md(d_position,
     d_force,
     d_neighborList,
     nAtom,
     maxNeighbors,
     lj1,
     lj2,
     cutsq);

  // Copy results back for correctness check
  cudaMemcpy(h_force, d_force, nAtom * sizeof(FORCEVECTYPE), cudaMemcpyDeviceToHost);

  std::cout << "Performing Correctness Check (may take several minutes)\n";

  checkResults<FPTYPE, FORCEVECTYPE, POSVECTYPE>(h_force, h_position, h_neighborList, nAtom);

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < iteration; i++) {
    md(d_position,
       d_force,
       d_neighborList,
       nAtom,
       maxNeighbors,
       lj1,
       lj2,
       cutsq);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average kernel execution time " << (time * 1e-9f) / iteration << " (s)\n";

  // Cleanup
  cudaFree(d_position);
  cudaFree(d_force);
  cudaFree(d_neighborList);

  free(h_position);
  free(h_force);
  free(h_neighborList);

  return 0;
}

